function MealPlanner() {
  const days = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
  const meals = ['Breakfast','Lunch','Dinner'];
  const [plan, setPlan] = React.useState({
    Mon:{Breakfast:'REPLACE_WITH_B_MON',Lunch:'REPLACE_WITH_L_MON',Dinner:'REPLACE_WITH_D_MON'},
    Tue:{Breakfast:'Oatmeal',Lunch:'Salad',Dinner:'Pasta'},
    Wed:{Breakfast:'Eggs',Lunch:'Sandwich',Dinner:'Curry'},
    Thu:{Breakfast:'Toast',Lunch:'Soup',Dinner:'Stir-fry'},
    Fri:{Breakfast:'Pancakes',Lunch:'Bowl',Dinner:'Pizza'},
    Sat:{Breakfast:'Bagels',Lunch:'Tacos',Dinner:'Burgers'},
    Sun:{Breakfast:'Waffles',Lunch:'Roast',Dinner:'Fish'}
  });

  const update = (day, meal, val) => {
    setPlan(p=>({...p,[day]:{...p[day],[meal]:val}}));
  };

  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Meal Planner</div>
      <div style={{flex:1,overflow:'auto'}}>
        <div style={{display:'grid',gridTemplateColumns:'80px repeat(3,1fr)',gap:4,minWidth:400}}>
          <div style={{fontWeight:700,fontSize:12,color:'#888',padding:4}}>Day</div>
          {meals.map(m=><div key={m} style={{fontWeight:700,fontSize:12,color:'#888',padding:4}}>{m}</div>)}
          {days.map(day=> (
            <React.Fragment key={day}>
              <div style={{fontWeight:600,fontSize:13,padding:6,background:'#f5f5f5',borderRadius:6,display:'flex',alignItems:'center'}}>{day}</div>
              {meals.map(meal=> (
                <input key={meal} value={plan[day]?.[meal]||''}
                  onChange={e=>update(day,meal,e.target.value)}
                  style={{padding:6,borderRadius:6,border:'1px solid #ddd',fontSize:12}}/>
              ))}
            </React.Fragment>
          ))}
        </div>
      </div>
    </div>
  );
}
render(<MealPlanner/>);
